<script setup>
import { ref } from 'vue';import { Head } from '@inertiajs/vue3';import axios from 'axios';import ParticipantPortalLayout from '@/Layouts/ParticipantPortalLayout.vue';
const props=defineProps({participations:Array,documents:Array,categories:Object});const items=ref([...props.documents]);const participationId=ref(props.participations[0]?.id||'');const category=ref('other');const file=ref(null);const uploading=ref(false);const message=ref('');const error=ref('');
const upload=async()=>{if(!file.value||!participationId.value)return;uploading.value=true;message.value='';error.value='';const data=new FormData();data.append('project_person_id',participationId.value);data.append('category',category.value);data.append('file',file.value);try{const r=await axios.post(route('participant-portal.documents.store'),data,{headers:{'Content-Type':'multipart/form-data'}});items.value.unshift(r.data.document);file.value=null;message.value=r.data.message;}catch(e){error.value=e.response?.data?.message||'Das Dokument konnte nicht hochgeladen werden.';}finally{uploading.value=false;}};
const remove=async(doc)=>{await axios.delete(route('participant-portal.documents.destroy',doc.id));items.value=items.value.filter(i=>i.id!==doc.id)};const statusLabel={pending:'Wird geprüft',approved:'Freigegeben',rejected:'Abgelehnt'};const statusClass={pending:'bg-amber-50 text-amber-700 ring-amber-200',approved:'bg-emerald-50 text-emerald-700 ring-emerald-200',rejected:'bg-rose-50 text-rose-700 ring-rose-200'};
</script>
<template><Head title="Dokumente"/><ParticipantPortalLayout title="Meine Dokumente" subtitle="Laden Sie Unterlagen sicher hoch und verfolgen Sie deren Freigabestatus."><div class="grid gap-6 xl:grid-cols-[400px_1fr]"><section class="h-fit rounded-2xl border border-slate-200 bg-white p-6 shadow-sm"><div class="grid h-12 w-12 place-items-center rounded-2xl bg-gradient-to-br from-orange-400 to-rose-500 text-xl text-white">＋</div><h2 class="mt-4 text-lg font-bold">Dokument hochladen</h2><p class="mt-1 text-sm leading-6 text-slate-500">PDF, Word oder Bild bis 10 MB. Neue Dateien werden zunächst durch Ihr Projektteam geprüft.</p><div class="mt-5 space-y-4"><label class="block text-sm font-semibold text-slate-700">Projekt<select v-model="participationId" class="mt-1.5 w-full rounded-xl border-slate-300 text-sm"><option v-for="p in participations" :key="p.id" :value="p.id">{{ p.projekt.name }}</option></select></label><label class="block text-sm font-semibold text-slate-700">Kategorie<select v-model="category" class="mt-1.5 w-full rounded-xl border-slate-300 text-sm"><option v-for="(label,key) in categories" :key="key" :value="key">{{ label }}</option></select></label><label class="block cursor-pointer rounded-2xl border-2 border-dashed border-slate-300 bg-slate-50 p-6 text-center hover:border-cyan-400 hover:bg-cyan-50"><input type="file" accept=".pdf,.doc,.docx,.jpg,.jpeg,.png" class="sr-only" @change="file=$event.target.files[0]"/><span class="block font-semibold text-slate-700">{{ file?.name || 'Datei auswählen' }}</span><span class="mt-1 block text-xs text-slate-500">Klicken, um eine Datei zu wählen</span></label><p v-if="message" class="rounded-xl bg-emerald-50 p-3 text-sm text-emerald-700">{{ message }}</p><p v-if="error" class="rounded-xl bg-rose-50 p-3 text-sm text-rose-700">{{ error }}</p><button type="button" class="w-full rounded-xl bg-slate-950 px-4 py-3 text-sm font-bold text-white disabled:opacity-50" :disabled="uploading||!file" @click="upload">{{ uploading?'Wird hochgeladen …':'Sicher hochladen' }}</button></div></section><section class="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm"><div class="flex items-center justify-between"><div><h2 class="text-lg font-bold">Ihre Unterlagen</h2><p class="text-sm text-slate-500">{{ items.length }} Dokumente</p></div></div><div v-if="items.length" class="mt-5 divide-y divide-slate-100"><article v-for="doc in items" :key="doc.id" class="flex flex-wrap items-center justify-between gap-4 py-4 first:pt-0"><div class="flex min-w-0 items-center gap-3"><div class="grid h-11 w-11 shrink-0 place-items-center rounded-xl bg-slate-100 text-lg">▤</div><div class="min-w-0"><p class="truncate font-semibold">{{ doc.original_name }}</p><p class="mt-1 text-xs text-slate-500">{{ categories[doc.category]||doc.category }} · {{ doc.participation?.projekt?.name }} · {{ Math.ceil(doc.size/1024) }} KB</p><p v-if="doc.review_note" class="mt-1 text-xs text-slate-500">{{ doc.review_note }}</p></div></div><div class="flex items-center gap-2"><span class="rounded-full px-2.5 py-1 text-xs font-bold ring-1" :class="statusClass[doc.status]">{{ statusLabel[doc.status] }}</span><a :href="route('participant-portal.documents.download',doc.id)" class="rounded-lg border border-slate-200 px-3 py-2 text-xs font-semibold hover:bg-slate-50">Download</a><button v-if="doc.status==='pending'" type="button" class="px-2 py-2 text-xs font-semibold text-rose-600" @click="remove(doc)">Löschen</button></div></article></div><div v-else class="mt-5 rounded-2xl border-2 border-dashed border-slate-200 p-10 text-center"><p class="font-semibold text-slate-700">Noch keine Dokumente</p><p class="mt-1 text-sm text-slate-500">Ihre hochgeladenen Unterlagen erscheinen hier.</p></div></section></div></ParticipantPortalLayout></template>
